parameters.jsCode:
const body = $input.first().json.body;

// Extrai texto da mensagem (suporte a texto simples e texto com formatação)
const msg = (
  body?.data?.message?.conversation ||
  body?.data?.message?.extendedTextMessage?.text ||
  ""
).trim();

// Ignora mensagens vazias ou de sistema
if (!msg || msg.length < 5) {
  return [{ json: { valido: false, motivo: "mensagem vazia", msg_original: msg } }];
}

const partes = msg.split("|").map(p => p.trim());
const tipo = partes[0]?.toUpperCase();
const numero = body?.data?.key?.remoteJid || "";
const pushName = body?.data?.pushName || "Alguém";

// ── REAL (atualiza valor real de um lançamento existente)
if (tipo === "REAL") {
  if (partes.length < 4) {
    return [{ json: { valido: false, motivo: "formato REAL incorreto", msg_original: msg, numero } }];
  }
  return [{ json: {
    valido: true,
    acao: "atualizar_real",
    tipo: "REAL",
    data: partes[1],
    categoria: partes[2],
    real: partes[3].replace(",", "."),
    responsavel: partes[4] || "",
    numero,
    pushName,
    msg_original: msg
  }}];
}

// ── GASTO ou RECEITA (novo lançamento)
if (tipo === "GASTO" || tipo === "RECEITA") {
  if (partes.length < 5) {
    return [{ json: { valido: false, motivo: "formato incorreto", msg_original: msg, numero } }];
  }

  const fixo = (partes[7] || "N").toUpperCase();
  const mes_inicio = partes[8] ? parseInt(partes[8]) : "";
  const mes_fim = partes[9] ? parseInt(partes[9]) : "";

  return [{ json: {
    valido: true,
    acao: "inserir",
    tipo,
    data: partes[1],
    categoria: partes[2],
    previsto: partes[3].replace(",", ".") || "0",
    real: partes[4].replace(",", ".") || "0",
    responsavel: partes[5] || "",
    obs: partes[6] || "",
    fixo,
    mes_inicio,
    mes_fim,
    numero,
    pushName,
    msg_original: msg
  }}];
}

// Tipo não reconhecido
return [{ json: {
  valido: false,
  motivo: "tipo não reconhecido (use GASTO, RECEITA ou REAL)",
  msg_original: msg,
  numero
}}];

